const codeGS = `/**
 * MasterHttpRelay — Google Apps Script
 *
 * DEPLOYMENT:
 *   1. Go to https://script.google.com → New project
 *   2. Delete the default code, paste THIS entire file
 *   3. Click Deploy → New deployment
 *   4. Type: Web app  |  Execute as: Me  |  Who has access: Anyone
 *   5. Copy the Deployment ID into config.json as "script_id"
 *
 * CHANGE THE AUTH KEY BELOW TO YOUR OWN SECRET!
 */

const AUTH_KEY = "CHANGE_ME_TO_A_STRONG_SECRET";

// Keep browser capability headers (sec-ch-ua*, sec-fetch-*) intact.
// Some modern apps, notably Google Meet, use them for browser gating.
// Headers that reveal the user's real IP are also stripped here as a
// second line of defence (the Python client strips them first).
const SKIP_HEADERS = {
  host: 1, connection: 1, "content-length": 1,
  "transfer-encoding": 1, "proxy-connection": 1, "proxy-authorization": 1,
  "priority": 1, te: 1,
  // IP-leaking / proxy-metadata headers
  "x-forwarded-for": 1, "x-forwarded-host": 1, "x-forwarded-proto": 1,
  "x-forwarded-port": 1, "x-real-ip": 1, "forwarded": 1, "via": 1,
  // Internal relay hop-count header — must not be forwarded to target sites.
  "x-mhr-hop": 1,
  // UrlFetchApp does not decompress gzip/br/deflate responses — stripping
  // accept-encoding forces targets to reply with plain (uncompressed) bodies
  // so the relay never has to handle compressed content it cannot decode.
  "accept-encoding": 1,
};

// Pattern that matches any Google Apps Script execution endpoint.
// Used to detect relay loops when an exit node is misconfigured to
// point back at a GAS deployment.
var _GAS_URL_RE = /^https?:\/\/script\.google\.com\/macros\//i;

// If fetchAll fails, only retry methods that are safe to replay.
const SAFE_REPLAY_METHODS = { GET: 1, HEAD: 1, OPTIONS: 1 };

function doPost(e) {
  try {
    var req = JSON.parse(e.postData.contents);
    if (req.k !== AUTH_KEY) return _json({ e: "unauthorized" });

    // Batch mode: { k, q: [...] }
    if (Array.isArray(req.q)) return _doBatch(req.q);

    // Single mode
    return _doSingle(req);
  } catch (err) {
    return _json({ e: String(err) });
  }
}

// Compress a byte array with gzip to reduce bytes-on-wire over DPI-shaped
// connections. Returns {b: byteArray, gz: true} if compression saves space,
// otherwise {b: original, gz: false}. This can cut text payloads by 60-80%.
function _maybeGzip(bytes) {
  try {
    var compressed = Utilities.gzip(Utilities.newBlob(bytes)).getBytes();
    if (compressed.length < bytes.length) {
      return { b: compressed, gz: true };
    }
  } catch (e) {
    // Gzip failed — fall through to uncompressed
  }
  return { b: bytes, gz: false };
}

function _doSingle(req) {
  if (!req.u || typeof req.u !== "string" || !req.u.match(/^https?:\/\//i)) {
    return _json({ e: "bad url" });
  }
  // Loop guard: refuse to relay back to any Apps Script deployment.
  // This fires when an exit node URL is misconfigured to point at a GAS
  // script — without this check the script would call itself indefinitely
  // and burn through the daily UrlFetch quota in seconds.
  if (_GAS_URL_RE.test(req.u)) {
    return _json({ e: "loop detected: relay target cannot be a Google Apps Script URL" });
  }
  var opts = _buildOpts(req);
  var resp = UrlFetchApp.fetch(req.u, opts);
  var gz = _maybeGzip(resp.getContent());
  var result = {
    s: resp.getResponseCode(),
    h: _respHeaders(resp),
    b: Utilities.base64Encode(gz.b),
  };
  if (gz.gz) result.gz = 1;
  return _json(result);
}

function _doBatch(items) {
  var fetchArgs = [];
  var fetchIndex = [];
  var fetchMethods = [];
  var errorMap = {};

  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    if (!item || typeof item !== "object") {
      errorMap[i] = "bad item";
      continue;
    }
    if (!item.u || typeof item.u !== "string" || !item.u.match(/^https?:\/\//i)) {
      errorMap[i] = "bad url";
      continue;
    }
    if (_GAS_URL_RE.test(item.u)) {
      errorMap[i] = "loop detected: relay target cannot be a Google Apps Script URL";
      continue;
    }
    try {
      var opts = _buildOpts(item);
      opts.url = item.u;
      fetchArgs.push(opts);
      fetchIndex.push(i);
      fetchMethods.push(String(item.m || "GET").toUpperCase());
    } catch (err) {
      errorMap[i] = String(err);
    }
  }

  // fetchAll() processes all requests in parallel inside Google
  var responses = [];
  if (fetchArgs.length > 0) {
    try {
      responses = UrlFetchApp.fetchAll(fetchArgs);
    } catch (err) {
      // If fetchAll fails as a whole, degrade to per-item fetch so one bad
      // request does not poison the full batch.
      responses = [];
      for (var j = 0; j < fetchArgs.length; j++) {
        try {
          if (!SAFE_REPLAY_METHODS[fetchMethods[j]]) {
            errorMap[fetchIndex[j]] = "batch fetchAll failed; unsafe method not replayed";
            responses[j] = null;
            continue;
          }
          var fallbackReq = fetchArgs[j];
          var fallbackUrl = fallbackReq.url;
          var fallbackOpts = {};
          for (var key in fallbackReq) {
            if (Object.prototype.hasOwnProperty.call(fallbackReq, key) && key !== "url") {
              fallbackOpts[key] = fallbackReq[key];
            }
          }
          responses[j] = UrlFetchApp.fetch(fallbackUrl, fallbackOpts);
        } catch (singleErr) {
          errorMap[fetchIndex[j]] = String(singleErr);
          responses[j] = null;
        }
      }
    }
  }

  var results = [];
  var rIdx = 0;
  for (var i = 0; i < items.length; i++) {
    if (Object.prototype.hasOwnProperty.call(errorMap, i)) {
      results.push({ e: errorMap[i] });
    } else {
      var resp = responses[rIdx++];
      if (!resp) {
        results.push({ e: "fetch failed" });
      } else {
        var gz = _maybeGzip(resp.getContent());
        var item = {
          s: resp.getResponseCode(),
          h: _respHeaders(resp),
          b: Utilities.base64Encode(gz.b),
        };
        if (gz.gz) item.gz = 1;
        results.push(item);
      }
    }
  }
  return _json({ q: results });
}

function _buildOpts(req) {
  var opts = {
    method: (req.m || "GET").toLowerCase(),
    muteHttpExceptions: true,
    followRedirects: req.r !== false,
    validateHttpsCertificates: true,
    escaping: false,
  };
  // Always mark outgoing UrlFetchApp requests with a relay hop counter.
  // Exit nodes and downstream relays can inspect this header to detect
  // loops before consuming quota or making recursive calls.
  var headers = { "x-mhr-hop": "1" };
  if (req.h && typeof req.h === "object") {
    for (var k in req.h) {
      // Use call() so a crafted req.h that overrides hasOwnProperty cannot
      // bypass the check (prototype-pollution hardening).
      if (Object.prototype.hasOwnProperty.call(req.h, k) &&
          !SKIP_HEADERS[k.toLowerCase()]) {
        headers[k] = req.h[k];
      }
    }
  }
  opts.headers = headers;
  if (req.b) {
    opts.payload = Utilities.base64Decode(req.b);
    if (req.ct) opts.contentType = req.ct;
  }
  return opts;
}

function _respHeaders(resp) {
  try {
    if (typeof resp.getAllHeaders === "function") {
      return resp.getAllHeaders();
    }
  } catch (err) {}
  return resp.getHeaders();
}

function doGet(e) {
  return HtmlService.createHtmlOutput(
    "<!DOCTYPE html><html><head><title>My App</title></head>" +
      '<body style="font-family:sans-serif;max-width:600px;margin:40px auto">' +
      "<h1>Welcome</h1><p>This application is running normally.</p>" +
      "</body></html>"
  );
}

function _json(obj) {
  // HtmlService responses can stay on script.google.com for /dev, while
  // ContentService commonly bounces through script.googleusercontent.com.
  // The Python client extracts the JSON payload from the body either way.
  return HtmlService.createHtmlOutput(JSON.stringify(obj)).setXFrameOptionsMode(
    HtmlService.XFrameOptionsMode.ALLOWALL
  );
}
`

const codeWorker = `// MasterHttpRelay exit node for Cloudflare Workers.
// Deploy as HTTP endpoint and set PSK to a strong secret.

const PSK = "CHANGE_ME_TO_A_STRONG_SECRET";

const STRIP_HEADERS = new Set([
  "host",
  "connection",
  "content-length",
  "transfer-encoding",
  "proxy-connection",
  "proxy-authorization",
  "x-forwarded-for",
  "x-forwarded-host",
  "x-forwarded-proto",
  "x-forwarded-port",
  "x-real-ip",
  "forwarded",
  "via",
  // Internal relay hop header — must not propagate to the final target.
  "x-mhr-hop",
  // Workers cannot decompress gzip/br/deflate — stripping accept-encoding
  // forces targets to reply with plain bodies the Worker can forward as-is.
  "accept-encoding",
]);

function decodeBase64ToBytes(input) {
  const bin = atob(input);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

function encodeBytesToBase64(bytes) {
  let bin = "";
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin);
}

function sanitizeHeaders(h) {
  const out = {};
  if (!h || typeof h !== "object") return out;
  for (const [k, v] of Object.entries(h)) {
    if (!k) continue;
    if (STRIP_HEADERS.has(k.toLowerCase())) continue;
    out[k] = String(v ?? "");
  }
  return out;
}

export default {
  async fetch(req) {
    try {
      // Cloudflare dashboard and browsers commonly test a Worker with GET.
      // Return a friendly health response so users don't misread it as failure.
      if (req.method === "GET") {
        return Response.json(
          {
            ok: true,
            status: "healthy",
            message: "Everything is OK. Worker is deployed and reachable.",
            usage: "Send POST with relay payload for actual proxy requests.",
          },
          { status: 200 }
        );
      }

      if (req.method !== "POST") {
        return Response.json(
          {
            e: "method_not_allowed",
            message: "Use POST for relay requests. GET is only a health check.",
          },
          { status: 405 }
        );
      }

      const body = await req.json();
      if (!body || typeof body !== "object") {
        return Response.json({ e: "bad_json" }, { status: 400 });
      }

      if (!PSK) {
        return Response.json({ e: "server_psk_missing" }, { status: 500 });
      }

      const k = String(body.k ?? "");
      const u = String(body.u ?? "");
      const m = String(body.m ?? "GET").toUpperCase();
      const h = sanitizeHeaders(body.h);
      const b64 = body.b;

      if (k !== PSK) return Response.json({ e: "unauthorized" }, { status: 401 });
      if (!/^https?:\/\//i.test(u)) return Response.json({ e: "bad_url" }, { status: 400 });

      // ── Loop detection ────────────────────────────────────────────────────
      // Case 1 — self-loop: target URL resolves back to this Worker.
      //   Happens when a user sets exit_node_url to the Worker URL itself.
      try {
        const targetHost = new URL(u).hostname.toLowerCase();
        const workerHost = new URL(req.url).hostname.toLowerCase();
        if (targetHost === workerHost) {
          return Response.json(
            { e: "loop_detected", detail: "target URL resolves to this Worker" },
            { status: 508 }
          );
        }
      } catch (_) {
        // Malformed URL already caught by the regex above; ignore parse errors.
      }
      // Case 2 — GAS→Worker→GAS loop: the incoming request was relayed from
      //   a Google Apps Script instance (x-mhr-hop header set), and the
      //   target is another Apps Script script URL.
      //   Without this guard, a misconfigured chain would bounce between
      //   Apps Script and Cloudflare until quota is exhausted.
      const hopHeader = req.headers.get("x-mhr-hop");
      if (hopHeader && /\/macros\/s\//i.test(u)) {
        return Response.json(
          { e: "loop_detected", detail: "GAS→Worker→GAS relay loop" },
          { status: 508 }
        );
      }

      let payload;
      if (typeof b64 === "string" && b64.length > 0) payload = decodeBase64ToBytes(b64);
      const requestBody = payload ? Uint8Array.from(payload) : undefined;

      const resp = await fetch(u, {
        method: m,
        headers: h,
        body: requestBody,
        redirect: "manual",
      });

      const data = new Uint8Array(await resp.arrayBuffer());
      const respHeaders = {};
      resp.headers.forEach((value, key) => {
        respHeaders[key] = value;
      });

      return Response.json({
        s: resp.status,
        h: respHeaders,
        b: encodeBytesToBase64(data),
      });
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      return Response.json({ e: message }, { status: 500 });
    }
  },
};
`

var (
	cfg          config.Config
	proxyServer  *proxy.Server
	proxyRunning bool
	logClients   = make(map[*websocket.Conn]bool)
	clientsMu    sync.Mutex
	upgrader     = websocket.Upgrader{
		CheckOrigin: func(r *http.Request) bool { return true },
	}
	guiHTML  []byte
	iconData []byte
	winHWND  unsafe.Pointer

	uiSettings = struct {
		Theme    string `json:"theme"`
		Language string `json:"language"`
		LogLevel string `json:"logLevel"`
	}{
		Theme:    "dark",
		Language: "fa",
		LogLevel: "INFO",
	}
	settingsPath string
)

func init() {
	// رمزگشایی آیکون
	var err error
	iconData, err = base64.StdEncoding.DecodeString(iconBase64)
	if err != nil {
		log.Println("Warning: failed to decode embedded icon")
		iconData = nil
	}

	// رمزگشایی HTML
	guiHTML, err = base64.StdEncoding.DecodeString(guiHTMLBase64)
	if err != nil {
		log.Println("ERROR: failed to decode embedded HTML. Using fallback.")
		guiHTML = []byte(`<html><body style="background:#202225;color:#dcddde;">MihaniRelay</body></html>`)
	}

	log.SetOutput(&logWriter{})
}

func loadUISettings() {
	docs := config.GetDocsDir()
	settingsPath = filepath.Join(docs, "settings.json")
	data, err := os.ReadFile(settingsPath)
	if err == nil {
		json.Unmarshal(data, &uiSettings)
	}
}

func saveUISettings() {
	docs := config.GetDocsDir()
	settingsPath = filepath.Join(docs, "settings.json")
	data, _ := json.MarshalIndent(uiSettings, "", "  ")
	os.WriteFile(settingsPath, data, 0644)
}

func loadIcon() {
	// قبلاً در init تنظیم شده است
}

func loadHTML() {
	// قبلاً در init تنظیم شده است
}

// ... (همه importها و ثابت‌ها بدون تغییر)

func StartGUI() {
	loadIcon()
	loadHTML()
	loadUISettings()

	cfg = config.Load()

	mux := http.NewServeMux()
	mux.HandleFunc("/", serveIndex)
	mux.HandleFunc("/icon.ico", serveIcon)
	mux.HandleFunc("/api/start", handleStart)
	mux.HandleFunc("/api/stop", handleStop)
	mux.HandleFunc("/api/config", handleConfig)
	mux.HandleFunc("/api/config/load", handleLoadConfig)
	mux.HandleFunc("/api/config/save", handleSaveConfig)
	mux.HandleFunc("/api/settings", handleSettings)
	mux.HandleFunc("/ws", handleWebSocket)
	mux.HandleFunc("/api/stats", handleStats)
	mux.HandleFunc("/api/scan", handleScan)
	mux.HandleFunc("/api/test", handleTest)
	mux.HandleFunc("/api/health", handleHealth)
	mux.HandleFunc("/api/ca/install", handleCAInstall)
	mux.HandleFunc("/api/ca/status", handleCAStatus)
	mux.HandleFunc("/api/set-proxy", handleSetSystemProxy)
	mux.HandleFunc("/api/code/script", handleCodeScript)
	mux.HandleFunc("/api/code/worker", handleCodeWorker)

	// GitHub & Xray
	RegisterGitHubHandlers(mux)
	// V2Ray
	RegisterV2RayHandlers(mux)

	listener, err := net.Listen("tcp", "127.0.0.1:0")
	if err != nil { panic(err) }
	port := listener.Addr().(*net.TCPAddr).Port

	go http.Serve(listener, mux)

	w := webview2.NewWithOptions(webview2.WebViewOptions{
		Debug:     false,
		AutoFocus: true,
		WindowOptions: webview2.WindowOptions{
			Title:  "MihaniRelay",
			Width:  1200,
			Height: 800,
			Center: true,
		},
	})
	if w == nil { panic("Failed to create WebView2 window") }
	defer w.Destroy()

	winHWND = w.Window()
	if winHWND != nil && len(iconData) > 0 {
		setWindowIcon(winHWND, iconData)
	}

	w.Navigate(fmt.Sprintf("http://127.0.0.1:%d", port))
	w.Run()
}

// ... (بقیه توابع موجود بدون تغییر)

func setWindowIcon(hwnd unsafe.Pointer, icoData []byte) {
	tmpFile, err := os.CreateTemp("", "mihani-icon-*.ico")
	if err != nil {
		return
	}
	defer os.Remove(tmpFile.Name())
	if _, err := tmpFile.Write(icoData); err != nil {
		tmpFile.Close()
		return
	}
	tmpFile.Close()

	user32 := syscall.NewLazyDLL("user32.dll")
	loadImage := user32.NewProc("LoadImageW")
	sendMessage := user32.NewProc("SendMessageW")
	pathPtr, _ := syscall.UTF16PtrFromString(tmpFile.Name())

	const IMAGE_ICON = 1
	const LR_LOADFROMFILE = 0x00000010
	const LR_DEFAULTSIZE = 0x00000040
	const WM_SETICON = 0x0080
	const ICON_SMALL = 0
	const ICON_BIG = 1

	hSmall, _, _ := loadImage.Call(0, uintptr(unsafe.Pointer(pathPtr)), IMAGE_ICON, 0, 0, LR_LOADFROMFILE)
	hBig, _, _ := loadImage.Call(0, uintptr(unsafe.Pointer(pathPtr)), IMAGE_ICON, 0, 0, LR_LOADFROMFILE|LR_DEFAULTSIZE)

	if hSmall != 0 {
		sendMessage.Call(uintptr(hwnd), WM_SETICON, ICON_SMALL, hSmall)
	}
	if hBig != 0 {
		sendMessage.Call(uintptr(hwnd), WM_SETICON, ICON_BIG, hBig)
	}
}

func serveIndex(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Write(guiHTML)
}

func serveIcon(w http.ResponseWriter, r *http.Request) {
	if len(iconData) == 0 {
		http.NotFound(w, r)
		return
	}
	w.Header().Set("Content-Type", "image/x-icon")
	w.Write(iconData)
}

func handleStart(w http.ResponseWriter, r *http.Request) {
	if proxyRunning {
		json.NewEncoder(w).Encode(map[string]string{"status": "already running"})
		return
	}
	if cfg.LanSharing {
		cfg.ListenHost = "0.0.0.0"
	}
	var err error
	proxyServer, err = proxy.NewServer(cfg)
	if err != nil {
		http.Error(w, err.Error(), 500)
		return
	}
	proxyRunning = true
	go func() {
		if err := proxyServer.Start(); err != nil {
			log.Println("Proxy error:", err)
			proxyRunning = false
			sendStatusUpdate()
		}
	}()
	sendStatusUpdate()
	json.NewEncoder(w).Encode(map[string]string{"status": "started"})
}

func handleStop(w http.ResponseWriter, r *http.Request) {
	if proxyRunning && proxyServer != nil {
		proxyServer.Stop()
		proxyRunning = false
		sendStatusUpdate()
		json.NewEncoder(w).Encode(map[string]string{"status": "stopped"})
	} else {
		json.NewEncoder(w).Encode(map[string]string{"status": "not running"})
	}
}

func handleConfig(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(cfg)
}

func handleLoadConfig(w http.ResponseWriter, r *http.Request) {
	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = cfg.Mode
	}
	c := config.LoadMode(mode)
	json.NewEncoder(w).Encode(c)
}

func handleSaveConfig(w http.ResponseWriter, r *http.Request) {
	var newCfg config.Config
	if err := json.NewDecoder(r.Body).Decode(&newCfg); err != nil {
		http.Error(w, "bad json", 400)
		return
	}
	if newCfg.Mode == "" {
		newCfg.Mode = cfg.Mode
	}
	config.SaveMode(newCfg)
	cfg = newCfg
	json.NewEncoder(w).Encode(map[string]string{"status": "saved"})
}

func handleSettings(w http.ResponseWriter, r *http.Request) {
	if r.Method == "GET" {
		json.NewEncoder(w).Encode(uiSettings)
		return
	}
	var s struct {
		Theme    string `json:"theme"`
		Language string `json:"language"`
		LogLevel string `json:"logLevel"`
	}
	if err := json.NewDecoder(r.Body).Decode(&s); err != nil {
		http.Error(w, "bad json", 400)
		return
	}
	if s.Theme != "" { uiSettings.Theme = s.Theme }
	if s.Language != "" { uiSettings.Language = s.Language }
	if s.LogLevel != "" { uiSettings.LogLevel = s.LogLevel }
	saveUISettings()
	json.NewEncoder(w).Encode(map[string]string{"status": "saved"})
}

func handleStats(w http.ResponseWriter, r *http.Request) {
	if proxyServer != nil {
		json.NewEncoder(w).Encode(proxyServer.Stats())
	} else {
		json.NewEncoder(w).Encode(map[string]uint64{"requests":0,"active":0,"bytes":0})
	}
}

func handleScan(w http.ResponseWriter, r *http.Request) {
	ips := []string{
		"216.239.38.120", "216.239.36.120", "216.239.34.120", "216.239.32.120",
		"142.250.185.196", "142.250.184.196", "142.250.74.196", "142.250.74.206",
		"172.217.16.196", "172.217.168.196", "172.217.164.196",
		"64.233.185.121", "64.233.185.138", "64.233.185.113", "64.233.185.100",
		"74.125.204.113", "74.125.204.138", "74.125.204.100",
		"173.194.219.113", "173.194.219.138", "173.194.219.100",
		"216.58.209.100", "216.58.209.110", "216.58.209.132",
	}
	type result struct {
		IP   string `json:"ip"`
		Ping string `json:"ping"`
		Err  string `json:"error,omitempty"`
	}
	var results []result
	for _, ip := range ips {
		start := time.Now()
		conn, err := net.DialTimeout("tcp", ip+":80", 2*time.Second)
		if err != nil {
			results = append(results, result{IP: ip, Ping: "-1", Err: err.Error()})
			continue
		}
		conn.Close()
		ms := float64(time.Since(start).Milliseconds())
		results = append(results, result{IP: ip, Ping: fmt.Sprintf("%.0f", ms)})
	}
	json.NewEncoder(w).Encode(results)
}

func handleTest(w http.ResponseWriter, r *http.Request) {
	if !proxyRunning || proxyServer == nil {
		json.NewEncoder(w).Encode(map[string]string{"status": "error", "message": "Proxy is not running"})
		return
	}
	start := time.Now()
	conn, err := net.DialTimeout("tcp", fmt.Sprintf("%s:%d", cfg.ListenHost, cfg.ListenPort), 3*time.Second)
	if err != nil {
		json.NewEncoder(w).Encode(map[string]string{"status": "error", "message": err.Error()})
		return
	}
	conn.Close()
	elapsed := float64(time.Since(start).Milliseconds())
	json.NewEncoder(w).Encode(map[string]interface{}{"status": "ok", "ping": fmt.Sprintf("%.0f", elapsed)})
}

func handleHealth(w http.ResponseWriter, r *http.Request) {
	scriptID := r.URL.Query().Get("id")
	authKey := r.URL.Query().Get("key")
	if scriptID == "" {
		scriptID = cfg.ScriptID
		authKey = cfg.AuthKey
	}
	if scriptID == "" || authKey == "" {
		json.NewEncoder(w).Encode(map[string]interface{}{"ok":false,"error":"Missing id or key","ping_ms":0})
		return
	}
	result := fronter.TestDeployment(cfg.GoogleIP, cfg.FrontDomain, scriptID, authKey)
	json.NewEncoder(w).Encode(result)
}

func handleCAInstall(w http.ResponseWriter, r *http.Request) {
	err := cert.InstallCACert()
	if err != nil {
		json.NewEncoder(w).Encode(map[string]string{"status": "error", "message": err.Error()})
		return
	}
	json.NewEncoder(w).Encode(map[string]string{"status": "ok", "message": "CA certificate installed. Restart browser."})
}

func handleCAStatus(w http.ResponseWriter, r *http.Request) {
	installed := cert.IsCAInstalled()
	json.NewEncoder(w).Encode(map[string]bool{"installed": installed})
}

func handleSetSystemProxy(w http.ResponseWriter, r *http.Request) {
	enable := r.URL.Query().Get("enable") == "true"
	proxyAddr := fmt.Sprintf("127.0.0.1:%d", cfg.ListenPort)
	k, err := registry.OpenKey(registry.CURRENT_USER,
		`Software\Microsoft\Windows\CurrentVersion\Internet Settings`,
		registry.SET_VALUE)
	if err != nil {
		json.NewEncoder(w).Encode(map[string]string{"status": "error", "message": err.Error()})
		return
	}
	defer k.Close()
	if enable {
		k.SetStringValue("ProxyServer", proxyAddr)
		k.SetDWordValue("ProxyEnable", 1)
	} else {
		k.SetDWordValue("ProxyEnable", 0)
		k.DeleteValue("ProxyServer")
	}
	notifyProxySettingsChanged()
	status := "proxy removed"
	if enable {
		status = "proxy set to " + proxyAddr
	}
	json.NewEncoder(w).Encode(map[string]string{"status": status})
}

func notifyProxySettingsChanged() {
	user32 := syscall.NewLazyDLL("user32.dll")
	sendMessageTimeout := user32.NewProc("SendMessageTimeoutW")
	const HWND_BROADCAST = 0xFFFF
	const WM_SETTINGCHANGE = 0x001A
	const SMTO_NORMAL = 0x0000
	lParamStr := "Software\\Microsoft\\Windows\\CurrentVersion\\Internet Settings"
	lParam, _ := syscall.UTF16PtrFromString(lParamStr)
	sendMessageTimeout.Call(
		uintptr(HWND_BROADCAST),
		uintptr(WM_SETTINGCHANGE),
		0,
		uintptr(unsafe.Pointer(lParam)),
		uintptr(SMTO_NORMAL),
		2000,
		0,
	)
}

func handleCodeScript(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/plain")
	w.Write([]byte(codeGS))
}

func handleCodeWorker(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/plain")
	w.Write([]byte(codeWorker))
}

func handleWebSocket(w http.ResponseWriter, r *http.Request) {
	conn, _ := upgrader.Upgrade(w, r, nil)
	clientsMu.Lock()
	logClients[conn] = true
	clientsMu.Unlock()
	sendWSMessage(conn, map[string]interface{}{"type": "status", "running": proxyRunning, "ping": getPing(), "mode": cfg.Mode})
	for {
		_, _, err := conn.ReadMessage()
		if err != nil {
			break
		}
	}
	conn.Close()
	clientsMu.Lock()
	delete(logClients, conn)
	clientsMu.Unlock()
}

func sendWSMessage(conn *websocket.Conn, msg interface{}) { conn.WriteJSON(msg) }

func broadcastWS(msg interface{}) {
	clientsMu.Lock()
	defer clientsMu.Unlock()
	for conn := range logClients {
		if err := conn.WriteJSON(msg); err != nil {
			conn.Close()
			delete(logClients, conn)
		}
	}
}

func sendStatusUpdate() {
	broadcastWS(map[string]interface{}{
		"type":    "status",
		"running": proxyRunning,
		"ping":    getPing(),
		"mode":    cfg.Mode,
	})
}

func getPing() string {
	start := time.Now()
	conn, _ := net.DialTimeout("tcp", cfg.GoogleIP+":80", 1*time.Second)
	if conn != nil {
		conn.Close()
		return fmt.Sprintf("%.0f", float64(time.Since(start).Milliseconds()))
	}
	return "-1"
}

func broadcastLog(msg string) { broadcastWS(map[string]interface{}{"type": "log", "text": msg}) }

type logWriter struct{}

func (lw *logWriter) Write(p []byte) (int, error) {
	fmt.Print(string(p))
	broadcastLog(string(p))
	return len(p), nil
}